export type PackageInfo = {
    package_id: string;
    name: string | null;
    version: string | null;
    package_json_path: string;
    package_root: string;
    is_used: boolean;
    dependency_type: 'direct' | 'transitive';
    size: number;
    modules: Array<string>;
    chunk_ids: Array<number>;
};
